#include <inttypes.h>
#include <stdint.h>
#include <stdio.h>

int main(void) {
    int64_t value;
    if (scanf("%" SCNd64, &value) != 1) return 1;
    uint64_t magnitude = value < 0 ? (uint64_t)(-(value + 1)) + 1u : (uint64_t)value;
    printf("%" PRIu64 "\n", magnitude);
    return 0;
}
